 47→// --- Parameter Types ---
 48→
 49→type CreatePolicyParams = {
 50→  title: string;
 51→  description?: string;
 52→  selector?: PolicySelector;
 53→  rules: PolicyRule[];
 54→  human_veto_required?: boolean;
 55→  max_ttl?: string;
 56→  createdBy: RecordId<"identity">;
 57→  workspace: RecordId<"workspace">;
 58→  supersedes?: RecordId<"policy">;
 59→};
 60→
 61→// --- Query Functions ---
 62→
 63→export async function loadActivePolicies(
 64→  surreal: Surreal,
 65→  identityId: RecordId<"identity">,
 66→  workspaceId: RecordId<"workspace">,
 67→): Promise<PolicyRecord[]> {
 68→  const identityResult = await surreal.query<
 69→    [Array<{ policies: PolicyRecord[] }>]
 70→  >(
 71→    `SELECT ->governing->policy.* AS policies FROM $identity;`,
 72→    { identity: identityId },
 73→  );
 74→
 75→  const workspaceResult = await surreal.query<
 76→    [Array<{ policies: PolicyRecord[] }>]
 77→  >(
 78→    `SELECT <-protects<-policy.* AS policies FROM $workspace;`,
 79→    { workspace: workspaceId },
 80→  );
 81→
 82→  const identityPolicies = identityResult[0]?.[0]?.policies ?? [];
 83→  const workspacePolicies = workspaceResult[0]?.[0]?.policies ?? [];
 84→
 85→  // Deduplicate by policy ID and filter active only
 86→  const seen = new Set<string>();
 87→  const result: PolicyRecord[] = [];
 88→  for (const policy of [...identityPolicies, ...workspacePolicies]) {
 89→    const id = policy.id.id as string;
 90→    if (!seen.has(id) && policy.status === "active") {
 91→      seen.add(id);
 92→      result.push(policy);
 93→    }
 94→  }
 95→  return result;
 96→}
 97→
 98→export async function listWorkspacePolicies(
 99→  surreal: Surreal,
100→  workspace: RecordId<"workspace">,
101→  statusFilter?: PolicyStatus,
102→): Promise<PolicyListItem[]> {
103→  const query = statusFilter
104→    ? "SELECT * FROM policy WHERE workspace = $ws AND status = $status ORDER BY created_at DESC;"
105→    : "SELECT * FROM policy WHERE workspace = $ws ORDER BY created_at DESC;";
106→
107→  const params: Record<string, unknown> = { ws: workspace };
108→  if (statusFilter) params.status = statusFilter;
109→
110→  const [rows] = await surreal.query<[PolicyRecord[]]>(query, params);
111→
112→  return (rows ?? []).map(toPolicyListItem);
113→}
