115→export async function createPolicy(
116→  surreal: Surreal,
117→  params: CreatePolicyParams,
118→): Promise<{ policyId: string; policyRecord: RecordId<"policy">; version: number }> {
119→  const policyId = `policy-${crypto.randomUUID()}`;
120→  const policyRecord = new RecordId("policy", policyId);
121→
122→  if (params.supersedes) {
123→    // Atomic version assignment inside a transaction to prevent TOCTOU race.
124→    // Two concurrent requests both reading the same source version would both
125→    // compute version N+1 and create duplicate drafts. The transaction:
126→    // 1. Checks no draft already supersedes this policy (rejects duplicates)
127→    // 2. Computes MAX(version)+1 from the chain atomically
128→    // 3. Creates the new draft
129→    const content: Record<string, unknown> = {
130→      title: params.title,
131→      description: params.description,
132→      version: 1, // placeholder — overwritten atomically inside transaction
133→      status: "draft",
134→      selector: params.selector ?? {},
135→      rules: params.rules,
136→      human_veto_required: params.human_veto_required ?? false,
137→      created_by: params.createdBy,
138→      workspace: params.workspace,
139→      supersedes: params.supersedes,
140→      created_at: new Date(),
141→    };
142→    if (params.max_ttl) content.max_ttl = params.max_ttl;
143→
144→    await surreal.query(
145→      `
146→      BEGIN TRANSACTION;
147→        LET $existing = (SELECT VALUE id FROM policy
148→            WHERE supersedes = $supersedes AND status IN ['draft', 'testing'] LIMIT 1)[0];
149→        IF $existing != NONE {
150→          THROW "an in-flight version already exists for this policy";
151→        };
152→        LET $maxVer = (SELECT VALUE version FROM policy
153→            WHERE workspace = $ws AND (id = $supersedes OR supersedes = $supersedes)
154→            ORDER BY version DESC LIMIT 1)[0] ?? 0;
155→        CREATE $policy CONTENT $content;
156→        UPDATE $policy SET version = $maxVer + 1;
157→      COMMIT TRANSACTION;
158→      `,
159→      {
160→        policy: policyRecord,
161→        ws: params.workspace,
162→        supersedes: params.supersedes,
163→        content,
164→      },
165→    );
166→
167→    // Read back the assigned version after the transaction commits.
168→    const [versionRows] = await surreal.query<[Array<{ version: number }>]>(
169→      "SELECT version FROM $policy;",
170→      { policy: policyRecord },
171→    );
172→    const version = versionRows[0]?.version ?? 1;
173→    return { policyId, policyRecord, version };
174→  }
175→
176→  // Non-versioned (first version) — no supersedes, always version 1.
177→  const content: Record<string, unknown> = {
178→    title: params.title,
179→    description: params.description,
180→    version: 1,
181→    status: "draft",
182→    selector: params.selector ?? {},
183→    rules: params.rules,
184→    human_veto_required: params.human_veto_required ?? false,
185→    created_by: params.createdBy,
186→    workspace: params.workspace,
187→    created_at: new Date(),
188→  };
189→  if (params.max_ttl) content.max_ttl = params.max_ttl;
190→
191→  await surreal.query("CREATE $policy CONTENT $content;", {
192→    policy: policyRecord,
193→    content,
194→  });
195→
196→  return { policyId, policyRecord, version: 1 };
197→}
