199→export async function activatePolicy(
200→  surreal: Surreal,
201→  policy: PolicyRecord,
202→  creatorId: RecordId<"identity">,
203→  workspaceId: RecordId<"workspace">,
204→): Promise<void> {
205→  const policyRecord = policy.id;
206→  const supersededRecord = policy.supersedes;
207→
208→  if (supersededRecord) {
209→    // D5: Version monotonicity check inside transaction to prevent TOCTOU race.
210→    // Two concurrent activations of drafts superseding the same policy would both
211→    // read the old version outside the transaction, both pass, and both commit —
212→    // violating the single-active-version invariant. Moving the guard into the
213→    // transaction makes the check-and-update atomic.
214→    await surreal.query(
215→      `
216→      BEGIN TRANSACTION;
217→        LET $currentStatus = (SELECT VALUE status FROM $policy)[0];
218→        IF $currentStatus NOT IN ['draft', 'testing'] {
219→          THROW string::concat("policy must be in draft or testing status to activate (current: ", <string> $currentStatus, ")");
220→        };
221→        LET $oldVer = (SELECT VALUE version FROM $oldPolicy)[0];
222→        IF $oldVer != NONE AND $policyVersion <= $oldVer {
223→          THROW string::concat("version ", <string> $policyVersion,
224→            " must be greater than superseded version ", <string> $oldVer);
225→        };
226→        UPDATE $policy SET status = 'active', updated_at = time::now();
227→        RELATE $creator->governing->$policy SET created_at = time::now();
228→        RELATE $policy->protects->$workspace SET created_at = time::now();
229→        UPDATE $oldPolicy SET status = 'superseded', updated_at = time::now();
230→        DELETE governing WHERE out = $oldPolicy;
231→        DELETE protects WHERE in = $oldPolicy;
232→      COMMIT TRANSACTION;
233→    `,
234→      {
235→        policy: policyRecord,
236→        creator: creatorId,
237→        workspace: workspaceId,
238→        oldPolicy: supersededRecord,
239→        policyVersion: policy.version,
240→      },
241→    );
242→  } else {
243→    await surreal.query(
244→      `
245→      BEGIN TRANSACTION;
246→        LET $currentStatus = (SELECT VALUE status FROM $policy)[0];
247→        IF $currentStatus NOT IN ['draft', 'testing'] {
248→          THROW string::concat("policy must be in draft or testing status to activate (current: ", <string> $currentStatus, ")");
249→        };
250→        UPDATE $policy SET status = 'active', updated_at = time::now();
251→        RELATE $creator->governing->$policy SET created_at = time::now();
252→        RELATE $policy->protects->$workspace SET created_at = time::now();
253→      COMMIT TRANSACTION;
254→    `,
255→      {
256→        policy: policyRecord,
257→        creator: creatorId,
258→        workspace: workspaceId,
259→      },
260→    );
261→  }
262→}
