264→export async function deprecatePolicy(
265→  surreal: Surreal,
266→  policyId: string,
267→): Promise<void> {
268→  const policyRecord = new RecordId("policy", policyId);
269→
270→  await surreal.query(
271→    `
272→    BEGIN TRANSACTION;
273→      LET $currentStatus = (SELECT VALUE status FROM $policy)[0];
274→      IF $currentStatus NOT IN ['active'] {
275→        THROW string::concat("policy must be in active status to deprecate (current: ", <string> $currentStatus, ")");
276→      };
277→      UPDATE $policy SET status = 'deprecated', updated_at = time::now();
278→      DELETE governing WHERE out = $policy;
279→      DELETE protects WHERE in = $policy;
280→    COMMIT TRANSACTION;
281→  `,
282→    { policy: policyRecord },
283→  );
284→}
