348→/**
349→ * Fetch all versioned policies in the workspace in one query, then walk the
350→ * supersedes chain in memory. Replaces N sequential DB round-trips with 1.
351→ */
352→async function resolveChainFromPool(
353→  surreal: Surreal,
354→  policy: PolicyRecord,
355→): Promise<PolicyRecord[]> {
356→  // Single round-trip: fetch all workspace policies that participate in any
357→  // supersedes relationship (as source or target). The LET subquery collects
358→  // IDs referenced as supersedes targets so root policies (which lack
359→  // supersedes themselves) are included in the pool.
360→  const [, pool] = await surreal.query<[unknown, PolicyRecord[]]>(
361→    `LET $targets = SELECT VALUE supersedes FROM policy WHERE workspace = $ws AND supersedes != NONE;
362→     SELECT * FROM policy WHERE workspace = $ws AND (
363→       supersedes != NONE OR id IN $targets OR id = $id
364→     ) ORDER BY version ASC;`,
365→    { ws: policy.workspace, id: policy.id },
366→  );
367→
368→  // Build lookup maps for in-memory traversal
369→  const byId = new Map<string, PolicyRecord>();
370→  const bySupersedes = new Map<string, PolicyRecord>(); // key = superseded policy id
371→  for (const p of pool) {
372→    byId.set(p.id.id as string, p);
373→    if (p.supersedes) {
374→      bySupersedes.set(p.supersedes.id as string, p);
375→    }
376→  }
377→
378→  // Ensure the starting policy is in the pool (it may lack supersedes)
379→  if (!byId.has(policy.id.id as string)) {
380→    byId.set(policy.id.id as string, policy);
381→  }
382→
383→  // Walk backward to root
384→  const chain: PolicyRecord[] = [];
385→  const seen = new Set<string>();
386→  let current: PolicyRecord | undefined = policy;
387→  const ancestors: PolicyRecord[] = [];
388→  while (current?.supersedes) {
389→    const parentId = current.supersedes.id as string;
390→    if (seen.has(parentId)) break;
391→    seen.add(parentId);
392→    const parent = byId.get(parentId);
393→    if (!parent) break;
394→    ancestors.unshift(parent);
395→    current = parent;
396→  }
397→
398→  chain.push(...ancestors);
399→  if (!seen.has(policy.id.id as string)) {
400→    seen.add(policy.id.id as string);
401→    chain.push(policy);
402→  }
403→
404→  // Walk forward to latest
405→  let latestId = policy.id.id as string;
406→  for (let i = 0; i < 50; i++) {
407→    const child = bySupersedes.get(latestId);
408→    if (!child) break;
409→    const childId = child.id.id as string;
410→    if (seen.has(childId)) break;
411→    seen.add(childId);
412→    chain.push(child);
413→    latestId = childId;
414→  }
415→
416→  chain.sort((a, b) => a.version - b.version);
417→  return chain;
418→}
