  9→// ---------------------------------------------------------------------------
 10→
 11→export type ValidationResult =
 12→  | { valid: true }
 13→  | { valid: false; errors: string[] };
 14→
 15→// ---------------------------------------------------------------------------
 16→// Constants
 17→// ---------------------------------------------------------------------------
 18→
 19→const VALID_OPERATORS = new Set([
 20→  "eq", "neq", "lt", "lte", "gt", "gte", "in", "not_in", "exists",
 21→]);
 22→
 23→const VALID_EFFECTS = new Set(["allow", "deny"]);
 24→
 25→// ---------------------------------------------------------------------------
 26→// Predicate validation
 27→// ---------------------------------------------------------------------------
 28→
 29→function isPlainObject(value: unknown): value is Record<string, unknown> {
 30→  return typeof value === "object" && value !== null && !Array.isArray(value);
 31→}
 32→
 33→function validatePredicate(predicate: unknown, ruleIndex: number, predicateLabel: string): string[] {
 34→  if (!isPlainObject(predicate)) {
 35→    return [`rule[${ruleIndex}].${predicateLabel}: condition must be an object with field, operator, and value`];
 36→  }
 37→
 38→  const errors: string[] = [];
 39→
 40→  if (typeof predicate.field !== "string" || predicate.field.trim() === "") {
 41→    errors.push(`rule[${ruleIndex}].${predicateLabel}: predicate must have a non-empty "field" string`);
 42→  }
 43→
 44→  if (typeof predicate.operator !== "string" || !VALID_OPERATORS.has(predicate.operator)) {
 45→    errors.push(
 46→      `rule[${ruleIndex}].${predicateLabel}: predicate operator must be one of ${[...VALID_OPERATORS].join(", ")}`,
 47→    );
 48→  }
 49→
 50→  if (!("value" in predicate)) {
 51→    errors.push(`rule[${ruleIndex}].${predicateLabel}: predicate must have a "value" property`);
 52→  }
 53→
 54→  return errors;
 55→}
 56→
 57→function validateCondition(condition: unknown, ruleIndex: number): string[] {
 58→  if (Array.isArray(condition)) {
 59→    if (condition.length === 0) {
 60→      return [`rule[${ruleIndex}].condition: array condition must have at least one predicate`];
 61→    }
 62→    return condition.flatMap((pred, i) =>
 63→      validatePredicate(pred, ruleIndex, `condition[${i}]`),
 64→    );
 65→  }
 66→
 67→  return validatePredicate(condition, ruleIndex, "condition");
 68→}
 69→
 70→// ---------------------------------------------------------------------------
 71→// Rule validation
 72→// ---------------------------------------------------------------------------
 73→
 74→function validateRule(rule: unknown, index: number): string[] {
 75→  if (!isPlainObject(rule)) {
 76→    return [`rule[${index}]: must be an object`];
 77→  }
 78→
 79→  const errors: string[] = [];
 80→
 81→  // ID
 82→  if (typeof rule.id !== "string" || (rule.id as string).trim() === "") {
 83→    errors.push(`rule[${index}]: id must be a non-empty string`);
 84→  }
 85→
 86→  // Priority
 87→  if (typeof rule.priority !== "number" || !Number.isFinite(rule.priority)) {
 88→    errors.push(`rule[${index}]: priority must be a finite number`);
 89→  }
 90→
 91→  // Effect
 92→  if (!VALID_EFFECTS.has(rule.effect as string)) {
 93→    errors.push(`rule[${index}]: effect must be "allow" or "deny"`);
 94→  }
 95→
 96→  // Condition
 97→  errors.push(...validateCondition(rule.condition, index));
 98→
 99→  return errors;
100→}
