102→// ---------------------------------------------------------------------------
103→// Top-level body validation
104→// ---------------------------------------------------------------------------
105→
106→type PolicyCreateInput = {
107→  title: unknown;
108→  description: unknown;
109→  rules: unknown;
110→};
111→
112→export function validatePolicyCreateBody(body: PolicyCreateInput): ValidationResult {
113→  if (body === null || body === undefined) {
114→    return { valid: false, errors: ["request body is required"] };
115→  }
116→
117→  const errors: string[] = [];
118→
119→  // Title
120→  if (typeof body.title !== "string" || body.title.trim() === "") {
121→    errors.push("title is required and must be a non-empty string");
122→  }
123→
124→  // Description
125→  if (typeof body.description !== "string" || body.description.trim() === "") {
126→    errors.push("description is required and must be a non-empty string");
127→  }
128→
129→  // Rules
130→  if (!Array.isArray(body.rules) || body.rules.length === 0) {
131→    errors.push("at least one rule is required");
132→  } else {
133→    for (let i = 0; i < body.rules.length; i++) {
134→      errors.push(...validateRule(body.rules[i], i));
135→    }
136→  }
137→
138→  return errors.length === 0
139→    ? { valid: true }
140→    : { valid: false, errors };
141→}
